import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import {
  vertexShader,
  grassFragmentShader,
  waterFragmentShader,
  cloudFragmentShader,
  starFragmentShader
} from './shaders';

import bgGrass from '../../images/bg_grass_light.webp';
import bgGrassDark from '../../images/bg_grass_dark.webp';
import bgWater from '../../images/bg_water_light.webp';
import bgWaterDark from '../../images/bg_water_dark.webp';
import bgSky from '../../images/bg_sky_light.webp';
import bgSkyDark from '../../images/bg_sky_dark.webp';

interface ShaderBackgroundProps {
  mode: 'day' | 'night' | '';
}

type LayerKey = 'grass' | 'water' | 'sky';

const ShaderBackground: React.FC<ShaderBackgroundProps> = ({ mode }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    if (window.matchMedia?.('(prefers-reduced-motion: reduce)').matches) return;

    const canvas = canvasRef.current;
    if (!canvas) return;

    let renderer: THREE.WebGLRenderer;
    try {
      renderer = new THREE.WebGLRenderer({
        canvas,
        antialias: false,
        alpha: true,
        powerPreference: 'low-power',
        premultipliedAlpha: false
      });
    } catch {
      return;
    }

    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 1.5));
    renderer.setSize(window.innerWidth, window.innerHeight, false);
    renderer.setClearColor(0x000000, 0);

    // The parallax `<div>`s render the same images as a fallback. Hide them
    // while the shader is active to avoid double-compositing (which over-brightens
    // textures with semi-transparent areas like the night sky stars).
    const parallaxContainer = document.querySelector<HTMLDivElement>('.parallax-container');
    const previousDisplay = parallaxContainer?.style.display ?? '';
    if (parallaxContainer) parallaxContainer.style.display = 'none';

    const scene = new THREE.Scene();
    const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);

    const isNight = mode === 'night';
    const skyFrag = isNight ? starFragmentShader : cloudFragmentShader;

    const loader = new THREE.TextureLoader();
    const loadTexture = (url: string, repeat: boolean): THREE.Texture => {
      const tex = loader.load(url);
      tex.minFilter = THREE.LinearFilter;
      tex.magFilter = THREE.LinearFilter;
      tex.generateMipmaps = false;
      tex.wrapS = repeat ? THREE.RepeatWrapping : THREE.ClampToEdgeWrapping;
      tex.wrapT = THREE.ClampToEdgeWrapping;
      return tex;
    };

    // All background images are authored at 3840x2160 (16:9).
    const TEXTURE_ASPECT = 16 / 9;

    const grassTexture = loadTexture(isNight ? bgGrassDark : bgGrass, false);

    const layers: Record<
      LayerKey,
      { mesh: THREE.Mesh; material: THREE.ShaderMaterial; texture: THREE.Texture }
    > = {
      sky: buildLayer(loadTexture(isNight ? bgSkyDark : bgSky, true), skyFrag, 0, false),
      water: buildLayer(loadTexture(isNight ? bgWaterDark : bgWater, true), waterFragmentShader, 1, false),
      grass: buildLayer(grassTexture, grassFragmentShader, 2, true, TEXTURE_ASPECT)
    };

    function buildLayer(
      texture: THREE.Texture,
      fragmentShader: string,
      renderOrder: number,
      withCover: boolean,
      texAspect: number = 1
    ) {
      const uniforms: Record<string, { value: number | THREE.Texture }> = {
        uTexture: { value: texture },
        uTime: { value: 0 }
      };
      if (withCover) {
        uniforms.uTexAspect = { value: texAspect };
        uniforms.uViewAspect = { value: window.innerWidth / window.innerHeight };
      }
      const material = new THREE.ShaderMaterial({
        vertexShader,
        fragmentShader,
        uniforms,
        transparent: true,
        depthTest: false,
        depthWrite: false
      });
      const mesh = new THREE.Mesh(new THREE.PlaneGeometry(2, 2), material);
      mesh.renderOrder = renderOrder;
      scene.add(mesh);
      return { mesh, material, texture };
    }

    const handleResize = () => {
      renderer.setSize(window.innerWidth, window.innerHeight, false);
      const va = window.innerWidth / window.innerHeight;
      if (layers.grass.material.uniforms.uViewAspect) {
        layers.grass.material.uniforms.uViewAspect.value = va;
      }
    };
    window.addEventListener('resize', handleResize);

    // Pause when the root element gets `.paused` or `.browser-open` class.
    const root = document.getElementById('mawmawmaw');
    let paused = false;
    const updatePaused = () => {
      if (!root) return;
      paused = root.classList.contains('paused') || root.classList.contains('browser-open');
    };
    updatePaused();
    const observer = root
      ? new MutationObserver(updatePaused)
      : null;
    if (observer && root) {
      observer.observe(root, { attributes: true, attributeFilter: ['class'] });
    }

    let rafId = 0;
    let lastT = performance.now();
    const tick = (now: number) => {
      const delta = (now - lastT) / 1000;
      lastT = now;
      if (!paused) {
        const t = layers.sky.material.uniforms.uTime.value + delta;
        layers.sky.material.uniforms.uTime.value = t;
        layers.water.material.uniforms.uTime.value = t;
        layers.grass.material.uniforms.uTime.value = t;
        renderer.render(scene, camera);
      }
      rafId = requestAnimationFrame(tick);
    };
    rafId = requestAnimationFrame(tick);

    return () => {
      cancelAnimationFrame(rafId);
      window.removeEventListener('resize', handleResize);
      observer?.disconnect();
      if (parallaxContainer) parallaxContainer.style.display = previousDisplay;
      (Object.keys(layers) as LayerKey[]).forEach((k) => {
        const l = layers[k];
        scene.remove(l.mesh);
        l.mesh.geometry.dispose();
        l.material.dispose();
        l.texture.dispose();
      });
      renderer.dispose();
    };
  }, [mode]);

  return <canvas ref={canvasRef} className="shader-background-canvas" aria-hidden="true" />;
};

export default React.memo(ShaderBackground);
